import gymnasium as gym
import numpy as np
from gymnasium import spaces


class FlatMinigridObsWrapper(gym.ObservationWrapper):
    def __init__(self, env):
        super().__init__(env)
        assert "image" in self.observation_space.spaces
        assert "direction" in self.observation_space.spaces
        img_shape = self.observation_space["image"].shape
        self.img_size = int(np.prod(img_shape))
        self.observation_space = spaces.Box(
            low=0.0, high=1.0, shape=(self.img_size + 4,), dtype=np.float32
        )

    def observation(self, obs):
        img = obs["image"].astype(np.float32) / 255.0
        direction = np.zeros(4, dtype=np.float32)
        direction[obs["direction"]] = 1.0
        return np.concatenate([img.flatten(), direction])


class ImgObsWrapper(gym.ObservationWrapper):
    """Return a Dict with image (channel-first float32) and direction one-hot."""

    def __init__(self, env):
        super().__init__(env)
        img_shape = self.observation_space["image"].shape  # (7, 7, 3)
        self.observation_space = spaces.Dict({
            "image": spaces.Box(
                low=0.0, high=255.0,
                shape=(img_shape[2], img_shape[0], img_shape[1]),
                dtype=np.float32
            ),
            "direction": spaces.Box(
                low=0.0, high=1.0, shape=(4,), dtype=np.float32
            ),
        })

    def observation(self, obs):
        img = np.transpose(obs["image"], (2, 0, 1)).astype(np.float32)
        direction = np.zeros(4, dtype=np.float32)
        direction[obs["direction"]] = 1.0
        return {"image": img, "direction": direction}


class FrameStackWrapper(gym.Wrapper):
    """Stack the last n_frames image observations along the channel dimension."""

    def __init__(self, env, n_frames=8):
        super().__init__(env)
        self.n_frames = n_frames
        img_space = env.observation_space.spaces["image"]
        dir_space = env.observation_space.spaces["direction"]
        self.observation_space = spaces.Dict({
            "image": spaces.Box(
                low=0.0, high=255.0,
                shape=(img_space.shape[0] * n_frames, img_space.shape[1], img_space.shape[2]),
                dtype=np.float32
            ),
            "direction": dir_space,
        })
        self.frames = None
        self._current_direction = None

    def reset(self, **kwargs):
        obs, info = self.env.reset(**kwargs)
        self.frames = [obs["image"]] * self.n_frames
        self._current_direction = obs["direction"]
        return self._get_obs(), info

    def step(self, action):
        obs, reward, terminated, truncated, info = self.env.step(action)
        self.frames.append(obs["image"])
        self.frames.pop(0)
        self._current_direction = obs["direction"]
        return self._get_obs(), reward, terminated, truncated, info

    def _get_obs(self):
        img = np.concatenate(self.frames, axis=0)
        return {"image": img, "direction": self._current_direction}
